{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/config_loader.py","content":"import json
from pathlib import Path, PurePosixPath

from config_merge import empty_fragment, finalize_config, merge_fragments
from config_schema import validate_document
from config_types import ConfigFragment, ServiceConfig


def _reject_nonstandard_constant(value: str) -> object:
    raise ValueError(f"invalid JSON numeric constant: {value}")


def _read_document(path: Path) -> object:
    try:
        return json.loads(
            path.read_text(),
            parse_constant=_reject_nonstandard_constant,
        )
    except FileNotFoundError:
        raise
    except (OSError, UnicodeError, json.JSONDecodeError, ValueError) as exc:
        raise ValueError(f"cannot read configuration: {path}") from exc


def _resolve_path(path: Path) -> Path:
    try:
        return path.resolve()
    except (OSError, RuntimeError) as exc:
        raise ValueError(f"cannot resolve configuration path: {path}") from exc


def _resolve_include(path: Path, include: str, root: Path) -> Path:
    candidate = _resolve_path(path.parent / Path(PurePosixPath(include)))
    try:
        candidate.relative_to(root)
    except ValueError as exc:
        raise ValueError("include resolves outside the configuration root") from exc
    return candidate


def _load_recursive(path: Path, root: Path, active: frozenset[Path]) -> ConfigFragment:
    resolved = _resolve_path(path)
    try:
        resolved.relative_to(root)
    except ValueError as exc:
        raise ValueError("configuration path is outside the root") from exc
    if resolved in active:
        raise ValueError("configuration include cycle")

    parsed = validate_document(_read_document(resolved))
    merged = empty_fragment()
    next_active = active | {resolved}
    for include in parsed.includes:
        included_path = _resolve_include(resolved, include, root)
        included = _load_recursive(included_path, root, next_active)
        merged = merge_fragments(merged, included)
    return merge_fragments(merged, parsed.fragment)


def load_config(entry_path: str | Path) -> ServiceConfig:
    entry = _resolve_path(Path(entry_path))
    fragment = _load_recursive(entry, entry.parent, frozenset())
    return finalize_config(fragment)
