{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/config_schema.py","content":"import math
from collections.abc import Mapping
from pathlib import PurePosixPath

from config_types import ConfigFragment, ParsedDocument


_TOP_LEVEL_KEYS = {"includes", "service", "limits", "labels"}
_SERVICE_KEYS = {"host", "port"}
_LIMIT_KEYS = {"timeout_seconds", "retries"}


def _validate_include(value: object) -> str:
    if not isinstance(value, str) or not value or "\\" in value or "\x00" in value:
        raise ValueError("include must be a non-empty POSIX path string")
    path = PurePosixPath(value)
    if path.is_absolute() or value.endswith("/"):
        raise ValueError("include must name a relative file")
    return value


def _validate_includes(value: object) -> tuple[str, ...]:
    if not isinstance(value, list):
        raise ValueError("includes must be a list")
    return tuple(_validate_include(item) for item in value)


def _validate_service(value: object) -> dict[str, object]:
    if not isinstance(value, Mapping) or not set(value).issubset(_SERVICE_KEYS):
        raise ValueError("invalid service section")
    result: dict[str, object] = {}
    if "host" in value:
        host = value["host"]
        if not isinstance(host, str) or not host:
            raise ValueError("host must be a non-empty string")
        result["host"] = host
    if "port" in value:
        port = value["port"]
        if isinstance(port, bool) or not isinstance(port, int) or not 1 <= port <= 65535:
            raise ValueError("port must be an integer in 1..65535")
        result["port"] = port
    return result


def _validate_limits(value: object) -> dict[str, object]:
    if not isinstance(value, Mapping) or not set(value).issubset(_LIMIT_KEYS):
        raise ValueError("invalid limits section")
    result: dict[str, object] = {}
    if "timeout_seconds" in value:
        timeout = value["timeout_seconds"]
        if (
            isinstance(timeout, bool)
            or not isinstance(timeout, (int, float))
            or not math.isfinite(timeout)
            or timeout <= 0
        ):
            raise ValueError("timeout_seconds must be finite and positive")
        result["timeout_seconds"] = float(timeout)
    if "retries" in value:
        retries = value["retries"]
        if isinstance(retries, bool) or not isinstance(retries, int) or retries < 0:
            raise ValueError("retries must be a non-negative integer")
        result["retries"] = retries
    return result


def _validate_labels(value: object) -> dict[str, str]:
    if not isinstance(value, Mapping):
        raise ValueError("labels must be an object")
    labels: dict[str, str] = {}
    for key, label_value in value.items():
        if not isinstance(key, str) or not key or not isinstance(label_value, str):
            raise ValueError("labels must map non-empty strings to strings")
        labels[key] = label_value
    return labels


def validate_document(raw: object) -> ParsedDocument:
    if not isinstance(raw, Mapping) or not set(raw).issubset(_TOP_LEVEL_KEYS):
        raise ValueError("invalid configuration document")
    includes = _validate_includes(raw["includes"]) if "includes" in raw else ()
    service = _validate_service(raw["service"]) if "service" in raw else {}
    limits = _validate_limits(raw["limits"]) if "limits" in raw else {}
    labels = _validate_labels(raw["labels"]) if "labels" in raw else {}
    return ParsedDocument(
        includes=includes,
        fragment=ConfigFragment(service=service, limits=limits, labels=labels),
    )
"}}
